"use client";

import React, { useState, useEffect } from "react";
import {
  LayoutDashboard,
  Package,
  Users,
  ClipboardList,
  RefreshCw,
  AlertCircle,
  TrendingUp,
  Clock,
  CheckCircle2,
  ChevronRight,
  PieChart,
  Activity,
} from "lucide-react";

export default function AdminDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchDashboardData = async () => {
    setLoading(true);
    setError(null);
    try {
      const token = localStorage.getItem("accessToken");
      const res = await fetch("http://localhost:5000/admin/dashboard", {
        headers: { Authorization: `Bearer ${token}` },
      });
      const result = await res.json();
      if (!res.ok) throw new Error(result.message || "Unauthorized");
      setData(result);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDashboardData();
  }, []);

  if (loading)
    return (
      <div className="flex h-screen w-full items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
          <p className="text-xs font-black uppercase tracking-widest text-slate-400">
            Processing Analytics...
          </p>
        </div>
      </div>
    );

  if (error || !data)
    return (
      <div className="flex h-screen w-full items-center justify-center p-6 text-center">
        <div>
          <AlertCircle className="mx-auto text-rose-500 mb-4" size={48} />
          <h2 className="text-xl font-black text-slate-800">
            Connection Failed
          </h2>
          <p className="text-slate-500 mt-2">{error}</p>
          <button
            onClick={fetchDashboardData}
            className="mt-6 px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold flex items-center gap-2 mx-auto"
          >
            <RefreshCw size={18} /> Reconnect
          </button>
        </div>
      </div>
    );

  const { users, items, claims } = data;

  // --- DERIVED ANALYTICS ---
  const verificationDebt = Math.round((items.pending / items.total) * 100);
  const claimResolutionRate = Math.round(
    ((claims.approved + claims.rejected) / claims.total) * 100,
  );
  const claimPressure = (
    claims.pending /
    (items.total - items.returned)
  ).toFixed(1);

  return (
    <div className="min-h-screen bg-[#f8fafc] p-6 lg:p-10">
      <div className="max-w-[1600px] mx-auto space-y-8">
        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">
              System Insights
            </h1>
            <p className="text-slate-500 font-medium">
              Derived from {items.total} total recorded items.
            </p>
          </div>
          <button
            onClick={fetchDashboardData}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold text-slate-600 hover:bg-slate-50 transition-all"
          >
            <RefreshCw size={14} /> Refresh Data
          </button>
        </div>

        {/* Top Analysis Bento Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {/* Efficiency Metric */}
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col justify-between">
            <div className="flex justify-between items-start">
              <div className="bg-emerald-50 text-emerald-600 p-3 rounded-2xl">
                <TrendingUp size={24} />
              </div>
              <span className="text-[10px] font-black bg-emerald-100 text-emerald-700 px-2 py-1 rounded-md uppercase">
                High
              </span>
            </div>
            <div className="mt-8">
              <h3 className="text-4xl font-black text-slate-800">
                {claimResolutionRate}%
              </h3>
              <p className="text-sm font-bold text-slate-500 mt-1">
                Resolution Rate
              </p>
              <div className="w-full bg-slate-100 h-2 rounded-full mt-4 overflow-hidden">
                <div
                  className="bg-emerald-500 h-full transition-all duration-1000"
                  style={{ width: `${claimResolutionRate}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Verification Warning */}
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] shadow-xl shadow-indigo-100 flex flex-col justify-between text-white">
            <div className="flex justify-between items-start">
              <div className="bg-white/20 p-3 rounded-2xl">
                <Clock size={24} />
              </div>
              <span className="text-[10px] font-black bg-white/20 px-2 py-1 rounded-md uppercase">
                Action Required
              </span>
            </div>
            <div className="mt-8">
              <h3 className="text-4xl font-black">{verificationDebt}%</h3>
              <p className="text-sm font-bold text-indigo-100 mt-1">
                Items Awaiting Verification
              </p>
              <p className="text-[10px] text-indigo-200 mt-4 leading-relaxed font-medium uppercase tracking-widest">
                {items.pending} units needing manual review
              </p>
            </div>
          </div>

          {/* User Growth/Admin Ratio */}
          <div className="bg-slate-900 p-8 rounded-[2.5rem] flex flex-col justify-between text-white">
            <div className="flex justify-between items-start">
              <div className="bg-white/10 p-3 rounded-2xl">
                <Users size={24} />
              </div>
            </div>
            <div className="mt-8">
              <h3 className="text-4xl font-black text-white">{users.total}</h3>
              <p className="text-sm font-bold text-slate-400 mt-1">
                Active Accounts
              </p>
              <div className="flex gap-4 mt-4">
                <div className="text-[10px] font-bold text-slate-500 border border-slate-700 px-2 py-1 rounded-md">
                  {users.admins} ADMINS
                </div>
                <div className="text-[10px] font-bold text-slate-500 border border-slate-700 px-2 py-1 rounded-md">
                  {users.verified} VERIFIED
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Data Tables Section */}
        <div className="grid lg:grid-cols-2 gap-8">
          {/* Recent Claims List */}
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="p-8 border-b border-slate-50 flex items-center justify-between">
              <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs flex items-center gap-2">
                <ClipboardList size={16} className="text-indigo-600" /> Recent
                Claims
              </h3>
              <ChevronRight size={18} className="text-slate-300" />
            </div>
            <div className="p-4 space-y-2">
              {/* Note: Map data.recentClaims here when backend is updated */}
              {[1, 2, 3].map((_, i) => (
                <div
                  key={i}
                  className="flex items-center justify-between p-4 hover:bg-slate-50 rounded-2xl transition-all cursor-pointer group"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600">
                      <Package size={18} />
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-700 leading-none mb-1">
                        Pending Item Review
                      </p>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                        Queue ID: #00{i + 1}
                      </p>
                    </div>
                  </div>
                  <span className="text-[10px] font-black px-2 py-1 bg-amber-50 text-amber-600 rounded-md">
                    WAITING
                  </span>
                </div>
              ))}
              <p className="text-center p-4 text-[10px] font-bold text-slate-400 italic">
                Backend update required to see live list.
              </p>
            </div>
          </div>

          {/* Recent Posts List */}
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="p-8 border-b border-slate-50 flex items-center justify-between">
              <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs flex items-center gap-2">
                <Activity size={16} className="text-emerald-500" /> Recent
                Activity
              </h3>
              <ChevronRight size={18} className="text-slate-300" />
            </div>
            <div className="p-4 space-y-2">
              {/* Note: Map data.recentPosts here when backend is updated */}
              <div className="flex gap-4 p-4">
                <div className="w-[2px] bg-slate-100 relative">
                  <div className="absolute top-0 -left-[4px] w-2.5 h-2.5 rounded-full bg-emerald-500 border-2 border-white"></div>
                </div>
                <div>
                  <p className="text-sm font-bold text-slate-700">
                    System Sync Successful
                  </p>
                  <p className="text-xs text-slate-400 mt-1">
                    The dashboard mapped {items.total} items correctly from
                    JSON.
                  </p>
                </div>
              </div>
              <div className="flex gap-4 p-4">
                <div className="w-[2px] bg-slate-100 relative">
                  <div className="absolute top-0 -left-[4px] w-2.5 h-2.5 rounded-full bg-indigo-500 border-2 border-white"></div>
                </div>
                <div>
                  <p className="text-sm font-bold text-slate-700">
                    Derived Data Ready
                  </p>
                  <p className="text-xs text-slate-400 mt-1">
                    Resolution rate calculated at {claimResolutionRate}%.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Derived Analysis Summary */}
        <div className="bg-emerald-50 border border-emerald-100 rounded-[2rem] p-8 flex items-center gap-6">
          <div className="bg-white p-4 rounded-2xl text-emerald-600 shadow-sm">
            <PieChart size={32} />
          </div>
          <div>
            <h4 className="font-black text-emerald-900 text-lg">
              Predictive Summary
            </h4>
            <p className="text-emerald-700/70 text-sm font-medium leading-relaxed max-w-2xl">
              Based on a claim pressure of{" "}
              <span className="font-bold text-emerald-900">
                {claimPressure}
              </span>
              , the system is currently handling claims efficiently. However,
              with{" "}
              <span className="font-bold text-emerald-900">
                {items.pending} unverified items
              </span>
              , the database is operating at{" "}
              <span className="font-bold text-emerald-900">
                {verificationDebt}%
              </span>{" "}
              of its verification capacity.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
